<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/pgsql164/conf/postgresql.conf:/etc/postgresql/postgresql.conf:Z</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
